module RefModule (
    input clk,
    input clr,
    input en,
    output [11:0] q
);

    reg [11:0] unused_q_reg;

    always @(posedge clk) begin
        if (clr)
            unused_q_reg <= 12'b0;
        else if (en)
            unused_q_reg <= unused_q_reg + 1;
    end

    assign q = unused_q_reg;

endmodule
